package com.readyroad.readyroadbackend.integration;

import com.readyroad.readyroadbackend.domain.entity.Category;
import com.readyroad.readyroadbackend.domain.entity.TrafficSign;
import com.readyroad.readyroadbackend.domain.repository.CategoryRepository;
import com.readyroad.readyroadbackend.domain.repository.TrafficSignRepository;
import com.readyroad.readyroadbackend.dto.response.TrafficSignResponse;
import com.readyroad.readyroadbackend.service.TrafficSignService;
import org.junit.jupiter.api.*;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.ActiveProfiles;
import org.springframework.transaction.annotation.Transactional;

import java.util.List;
import java.util.regex.Pattern;

import static org.assertj.core.api.Assertions.assertThat;

/**
 * Regression guard for Traffic Sign A1a data integrity.
 *
 * <p>
 * Ensures that A1a canonical data is correctly stored, retrieved, and
 * rendered through the full service to mapper to DTO pipeline, with no
 * escaped unicode sequences (backslash-uXXXX) in any multilingual field.
 * </p>
 *
 * <p>
 * Seeds its own A1a data into H2 to mirror what V86 does in production.
 * </p>
 */
@SpringBootTest
@ActiveProfiles("test")
@Transactional
@DisplayName("Feature: Traffic Sign A1a Data Integrity Regression Guard")
class TrafficSignA1aRegressionTest {

    // ── Canonical V6 / V86 values ──────────────────────
    private static final String SIGN_CODE = "A1a";
    private static final String CATEGORY_CODE = "A";
    private static final String NAME_EN = "Dangerous bend to the left";
    private static final String NAME_AR = "منعطف خطر لليسار";
    private static final String NAME_NL = "Gevaarlijke bocht naar links.";
    private static final String NAME_FR = "Virage dangereux à gauche";
    private static final String DESC_EN = "Dangerous bend to the left";
    private static final String DESC_AR = "منعطف خطر لليسار";
    private static final String DESC_NL = "Gevaarlijke bocht naar links.";
    private static final String DESC_FR = "Virage dangereux à gauche";
    private static final String LONG_DESC_EN = "Warning for a dangerous curve to the left at approximately 150 meters. Reduce your speed and pay attention.";
    private static final String LONG_DESC_AR = "تحذير من منعطف خطير إلى اليسار على مسافة 150 متر تقريباً. خفف من سرعتك وانتبه.";
    private static final String LONG_DESC_NL = "Waarschuwing voor een gevaarlijke bocht naar links op ongeveer 150 meter afstand. Verminder uw snelheid en let goed op.";
    private static final String LONG_DESC_FR = "Avertissement d'un virage dangereux à gauche à environ 150 mètres. Réduisez votre vitesse et soyez attentif.";

    /**
     * Detects literal escaped unicode sequences like \u0639 or \u00E9 in strings
     */
    private static final Pattern ESCAPED_UNICODE = Pattern.compile("\\\\u[0-9A-Fa-f]{4}");

    @Autowired
    private TrafficSignService trafficSignService;

    @Autowired
    private TrafficSignRepository trafficSignRepository;

    @Autowired
    private CategoryRepository categoryRepository;

    private TrafficSign a1a;

    @BeforeEach
    void seedA1a() {
        // Create category A if it doesn't exist
        Category categoryA = categoryRepository.findByCode(CATEGORY_CODE)
                .orElseGet(() -> {
                    Category cat = new Category();
                    cat.setCode(CATEGORY_CODE);
                    cat.setNameEn("Danger Signs");
                    cat.setNameAr("علامات الخطر");
                    cat.setNameNl("Gevaarsborden");
                    cat.setNameFr("Panneaux de danger");
                    cat.setIsActive(true);
                    cat.setDisplayOrder(1);
                    return categoryRepository.save(cat);
                });

        // If A1a already exists (from another test), delete it to start fresh
        trafficSignRepository.findBySignCode(SIGN_CODE)
                .ifPresent(trafficSignRepository::delete);
        trafficSignRepository.flush();

        // Insert A1a with canonical V86 data
        a1a = new TrafficSign();
        a1a.setSignCode(SIGN_CODE);
        a1a.setCategory(categoryA);
        a1a.setNameEn(NAME_EN);
        a1a.setNameAr(NAME_AR);
        a1a.setNameNl(NAME_NL);
        a1a.setNameFr(NAME_FR);
        a1a.setDescriptionEn(DESC_EN);
        a1a.setDescriptionAr(DESC_AR);
        a1a.setDescriptionNl(DESC_NL);
        a1a.setDescriptionFr(DESC_FR);
        a1a.setImageUrl("images/signs/danger_signs/A1a.png");
        a1a.setIsActive(true);
        a1a.setLongDescriptionEn(LONG_DESC_EN);
        a1a.setLongDescriptionAr(LONG_DESC_AR);
        a1a.setLongDescriptionNl(LONG_DESC_NL);
        a1a.setLongDescriptionFr(LONG_DESC_FR);
        a1a = trafficSignRepository.saveAndFlush(a1a);
    }

    // ── Scenario: API response correctness for A1a ─────

    @Nested
    @DisplayName("Scenario: Contract verification — API response correctness for A1a")
    class ContractVerification {

        @Test
        @DisplayName("Given A1a exists, When getSignByCode is called, Then response contains canonical names")
        void a1a_returns_canonical_names() {
            TrafficSignResponse response = trafficSignService.getSignByCode(SIGN_CODE);

            assertThat(response.signCode()).isEqualTo(SIGN_CODE);
            assertThat(response.nameEn()).isEqualTo(NAME_EN);
            assertThat(response.nameAr()).isEqualTo(NAME_AR);
            assertThat(response.nameNl()).isEqualTo(NAME_NL);
            assertThat(response.nameFr()).isEqualTo(NAME_FR);
        }

        @Test
        @DisplayName("Given A1a exists, When getSignByCode is called, Then all 4 descriptions are non-empty")
        void a1a_has_non_empty_descriptions() {
            TrafficSignResponse response = trafficSignService.getSignByCode(SIGN_CODE);

            assertThat(response.descriptionEn()).isNotBlank().isEqualTo(DESC_EN);
            assertThat(response.descriptionAr()).isNotBlank().isEqualTo(DESC_AR);
            assertThat(response.descriptionNl()).isNotBlank().isEqualTo(DESC_NL);
            assertThat(response.descriptionFr()).isNotBlank().isEqualTo(DESC_FR);
        }

        @Test
        @DisplayName("Given A1a has long descriptions, When getSignByCode is called, Then all 4 long descriptions are returned")
        void a1a_has_long_descriptions() {
            TrafficSignResponse response = trafficSignService.getSignByCode(SIGN_CODE);

            assertThat(response.longDescriptionEn()).isNotBlank().isEqualTo(LONG_DESC_EN);
            assertThat(response.longDescriptionAr()).isNotBlank().isEqualTo(LONG_DESC_AR);
            assertThat(response.longDescriptionNl()).isNotBlank().isEqualTo(LONG_DESC_NL);
            assertThat(response.longDescriptionFr()).isNotBlank().isEqualTo(LONG_DESC_FR);
        }

        @Test
        @DisplayName("Given A1a exists, When getSignByCode is called, Then category is A (Warning/Danger)")
        void a1a_has_correct_category() {
            TrafficSignResponse response = trafficSignService.getSignByCode(SIGN_CODE);

            assertThat(response.categoryCode()).isEqualTo(CATEGORY_CODE);
        }

        @Test
        @DisplayName("Given A1a isActive=true, Then it appears in getAllActiveSigns")
        void a1a_is_active_and_delivered() {
            List<TrafficSignResponse> allActive = trafficSignService.getAllActiveSigns();
            assertThat(allActive)
                    .extracting(TrafficSignResponse::signCode)
                    .contains(SIGN_CODE);
        }
    }

    // ── Scenario: No escaped unicode in multilingual fields ─

    @Nested
    @DisplayName("Scenario: Regression guard — no escaped unicode in response fields")
    class UnicodeRegressionGuard {

        @Test
        @DisplayName("Given A1a response, Then no field contains escaped backslash-u sequences")
        void a1a_response_has_no_escaped_unicode() {
            TrafficSignResponse response = trafficSignService.getSignByCode(SIGN_CODE);

            // Check every multilingual field for escaped unicode sequences
            assertNoEscapedUnicode("nameEn", response.nameEn());
            assertNoEscapedUnicode("nameAr", response.nameAr());
            assertNoEscapedUnicode("nameNl", response.nameNl());
            assertNoEscapedUnicode("nameFr", response.nameFr());
            assertNoEscapedUnicode("descriptionEn", response.descriptionEn());
            assertNoEscapedUnicode("descriptionAr", response.descriptionAr());
            assertNoEscapedUnicode("descriptionNl", response.descriptionNl());
            assertNoEscapedUnicode("descriptionFr", response.descriptionFr());
            assertNoEscapedUnicode("longDescriptionEn", response.longDescriptionEn());
            assertNoEscapedUnicode("longDescriptionAr", response.longDescriptionAr());
            assertNoEscapedUnicode("longDescriptionNl", response.longDescriptionNl());
            assertNoEscapedUnicode("longDescriptionFr", response.longDescriptionFr());
            assertNoEscapedUnicode("categoryCode", response.categoryCode());
        }

        @Test
        @DisplayName("Given A1a response, Then all multilingual fields are valid UTF-8 strings")
        void a1a_response_fields_are_valid_utf8() {
            TrafficSignResponse response = trafficSignService.getSignByCode(SIGN_CODE);

            // Arabic fields must contain Arabic characters (U+0600..U+06FF range)
            assertThat(response.nameAr())
                    .as("nameAr must contain Arabic script characters")
                    .matches(".*[\u0600-\u06FF].*");
            assertThat(response.descriptionAr())
                    .as("descriptionAr must contain Arabic script characters")
                    .matches(".*[\u0600-\u06FF].*");

            // French fields with accented characters must contain actual accented chars
            assertThat(response.nameFr()).contains("à");
            assertThat(response.descriptionFr()).contains("à");
        }

        @Test
        @DisplayName("Given all active signs, Then no sign has escaped unicode in any field")
        void no_active_sign_has_escaped_unicode() {
            List<TrafficSignResponse> allSigns = trafficSignService.getAllActiveSigns();
            assertThat(allSigns).isNotEmpty();

            for (TrafficSignResponse sign : allSigns) {
                String prefix = "sign[" + sign.signCode() + "].";
                assertNoEscapedUnicode(prefix + "nameEn", sign.nameEn());
                assertNoEscapedUnicode(prefix + "nameAr", sign.nameAr());
                assertNoEscapedUnicode(prefix + "nameNl", sign.nameNl());
                assertNoEscapedUnicode(prefix + "nameFr", sign.nameFr());
                if (sign.descriptionEn() != null)
                    assertNoEscapedUnicode(prefix + "descriptionEn", sign.descriptionEn());
                if (sign.descriptionAr() != null)
                    assertNoEscapedUnicode(prefix + "descriptionAr", sign.descriptionAr());
                if (sign.descriptionNl() != null)
                    assertNoEscapedUnicode(prefix + "descriptionNl", sign.descriptionNl());
                if (sign.descriptionFr() != null)
                    assertNoEscapedUnicode(prefix + "descriptionFr", sign.descriptionFr());
            }
        }
    }

    // ── Scenario: A1a is not confused with siblings ────

    @Nested
    @DisplayName("Scenario: A1a is distinct from A1b (no content swap)")
    class ContentSwapGuard {

        @Test
        @DisplayName("Given A1a, Then names do NOT contain 'right' or 'droite' or 'rechts' or 'لليمين'")
        void a1a_does_not_contain_right_direction_content() {
            TrafficSignResponse response = trafficSignService.getSignByCode(SIGN_CODE);

            // A1a = left bend. Must NOT contain right-direction text (that's A1b).
            assertThat(response.nameEn().toLowerCase()).doesNotContain("right");
            assertThat(response.nameFr().toLowerCase()).doesNotContain("droite");
            assertThat(response.nameNl().toLowerCase()).doesNotContain("rechts");
            assertThat(response.nameAr()).doesNotContain("لليمين");

            // Must contain left-direction text
            assertThat(response.nameEn().toLowerCase()).contains("left");
            assertThat(response.nameFr().toLowerCase()).contains("gauche");
            assertThat(response.nameNl().toLowerCase()).contains("links");
            assertThat(response.nameAr()).contains("لليسار");
        }

        @Test
        @DisplayName("Given A1a, Then names are NOT 'Speed bump' / 'مطب' (the previous wrong content)")
        void a1a_is_not_the_old_wrong_content() {
            TrafficSignResponse response = trafficSignService.getSignByCode(SIGN_CODE);

            assertThat(response.nameEn()).isNotEqualToIgnoringCase("Speed bump");
            assertThat(response.nameAr()).isNotEqualTo("مطب");
            assertThat(response.nameNl()).isNotEqualToIgnoringCase("Verkeersdrempel");
            assertThat(response.nameFr()).isNotEqualToIgnoringCase("Ralentisseur");
        }
    }

    // ── Helper ─────────────────────────────────────────

    private void assertNoEscapedUnicode(String fieldName, String value) {
        if (value == null)
            return;
        assertThat(ESCAPED_UNICODE.matcher(value).find())
                .as("Field '%s' must not contain escaped unicode sequences, but was: %s", fieldName, value)
                .isFalse();
    }
}

-- ============================================================
-- Migration: V141
-- Description: Fix all stale/wrong image URLs in traffic_signs and road_signs
--   that produce 404 errors in the frontend.
--
-- Root causes:
--   A) traffic_signs: image_url retained old descriptive filenames after
--      asset files were renamed to short canonical names.
--   B) road_signs: image_path uses non-existent folders ('aanwijzingsborden',
--      'zoneborden') instead of the correct ones ('information_signs', 'zone_signs').
--   C) D5/D7 have no image assets and no quiz questions; remove them.
-- ============================================================

-- ── A. traffic_signs: individual path fixes ──────────────────────────────────

-- C43: generic speed sign → use the 30 km canonical image
UPDATE traffic_signs
SET image_url = 'images/signs/prohibition_signs/C43 - Verbod te rijden met een grotere snelheid dan is aangeduid 30 km.png'
WHERE sign_code = 'C43';

-- D1b: was titled "rechts afslaan"; actual sign and file is "links afslaan"
UPDATE traffic_signs
SET image_url = 'images/signs/mandatory_signs/D1b Verplichting links afslaan.png'
WHERE sign_code = 'D1b';

-- F45b: long descriptive name → canonical short name
UPDATE traffic_signs
SET image_url = 'images/signs/information_signs/F45b.png'
WHERE sign_code = 'F45b';

-- F50b: was pointing at "F50bis...fietsers" (non-existent) → canonical F50b.png
UPDATE traffic_signs
SET image_url = 'images/signs/information_signs/F50b.png'
WHERE sign_code = 'F50b';

-- F79: missing "(met afstandsaanduiding)" suffix
UPDATE traffic_signs
SET image_url = 'images/signs/information_signs/F79 Tijdelijke verdeling van de rijstroken (met afstandsaanduiding).png'
WHERE sign_code = 'F79';

-- GIII-aquaplaning: old descriptive name → canonical short name
UPDATE traffic_signs
SET image_url = 'images/signs/additional_signs/GIII-aquaplaning.png'
WHERE sign_code = 'GIII-aquaplaning';

-- GVIId-CARPOOL
UPDATE traffic_signs
SET image_url = 'images/signs/additional_signs/GVIId-CARPOOL.png'
WHERE sign_code = 'GVIId-CARPOOL';

-- GVIId-PR
UPDATE traffic_signs
SET image_url = 'images/signs/additional_signs/GVIId-PR.png'
WHERE sign_code = 'GVIId-PR';

-- M12-richtingen
UPDATE traffic_signs
SET image_url = 'images/signs/additional_signs/M12-richtingen.png'
WHERE sign_code = 'M12-richtingen';

-- MARK-R3
UPDATE traffic_signs
SET image_url = 'images/signs/delineation_signs/MARK-R3.png'
WHERE sign_code = 'MARK-R3';

-- TYPE delineation signs: replace verbose descriptive names with short canonical names
UPDATE traffic_signs SET image_url = 'images/signs/delineation_signs/TYPE-IA1.png' WHERE sign_code = 'TYPE-IA1';
UPDATE traffic_signs SET image_url = 'images/signs/delineation_signs/TYPE-IA2.png' WHERE sign_code = 'TYPE-IA2';
UPDATE traffic_signs SET image_url = 'images/signs/delineation_signs/TYPE-IB1.png' WHERE sign_code = 'TYPE-IB1';
UPDATE traffic_signs SET image_url = 'images/signs/delineation_signs/TYPE-IB2.png' WHERE sign_code = 'TYPE-IB2';
UPDATE traffic_signs SET image_url = 'images/signs/delineation_signs/TYPE-IC.png'  WHERE sign_code = 'TYPE-IC';
UPDATE traffic_signs SET image_url = 'images/signs/delineation_signs/TYPE-IIB.png' WHERE sign_code = 'TYPE-IIB';
UPDATE traffic_signs SET image_url = 'images/signs/delineation_signs/TYPE-V.png'   WHERE sign_code = 'TYPE-V';
UPDATE traffic_signs SET image_url = 'images/signs/delineation_signs/TYPE-VA.png'  WHERE sign_code = 'TYPE-VA';

-- ZC21 (begin zone): missing dash before description
UPDATE traffic_signs
SET image_url = 'images/signs/zone_signs/ZC21 - Zone verboden toegang voor bestuurders van voertuigen waarvan de massa hoger is dan de aangeduide massa.png'
WHERE sign_code = 'ZC21';

-- ZC21-zone: was pointing at "Einde zone..." (wrong) → begin-zone file
UPDATE traffic_signs
SET image_url = 'images/signs/zone_signs/ZC21 - Zone verboden toegang voor bestuurders van voertuigen waarvan de massa hoger is dan de aangeduide massa.png'
WHERE sign_code = 'ZC21-zone';

-- ZC21T (einde zone): said "Zone" → should be "Einde zone"
UPDATE traffic_signs
SET image_url = 'images/signs/zone_signs/ZC21T Einde zone verboden toegang voor bestuurders van voertuigen waarvan de massa hoger is dan de aangeduide massa.png'
WHERE sign_code = 'ZC21T';

-- ZC35 (begin zone): non-existent descriptive name → canonical short name
UPDATE traffic_signs
SET image_url = 'images/signs/zone_signs/ZC35.png'
WHERE sign_code = 'ZC35';

-- ZC35T (einde zone): said "Zone" (begin) → should be "Einde zone"
UPDATE traffic_signs
SET image_url = 'images/signs/zone_signs/ZC35T Einde zone verboden inhalen.png'
WHERE sign_code = 'ZC35T';

-- ── B. road_signs: individual path fixes ─────────────────────────────────────

-- C43: same as traffic_signs fix
UPDATE road_signs
SET image_path = 'images/signs/prohibition_signs/C43 - Verbod te rijden met een grotere snelheid dan is aangeduid 30 km.png'
WHERE sign_code = 'C43';

-- F45b: long descriptive name → short canonical
UPDATE road_signs
SET image_path = 'images/signs/information_signs/F45b.png'
WHERE sign_code = 'F45b';

-- MARK-R3
UPDATE road_signs
SET image_path = 'images/signs/delineation_signs/MARK-R3.png'
WHERE sign_code = 'MARK-R3';

-- TYPE delineation signs
UPDATE road_signs SET image_path = 'images/signs/delineation_signs/TYPE-IA1.png' WHERE sign_code = 'TYPE-IA1';
UPDATE road_signs SET image_path = 'images/signs/delineation_signs/TYPE-IA2.png' WHERE sign_code = 'TYPE-IA2';
UPDATE road_signs SET image_path = 'images/signs/delineation_signs/TYPE-IB1.png' WHERE sign_code = 'TYPE-IB1';
UPDATE road_signs SET image_path = 'images/signs/delineation_signs/TYPE-IB2.png' WHERE sign_code = 'TYPE-IB2';
UPDATE road_signs SET image_path = 'images/signs/delineation_signs/TYPE-IC.png'  WHERE sign_code = 'TYPE-IC';
UPDATE road_signs SET image_path = 'images/signs/delineation_signs/TYPE-IIB.png' WHERE sign_code = 'TYPE-IIB';
UPDATE road_signs SET image_path = 'images/signs/delineation_signs/TYPE-V.png'   WHERE sign_code = 'TYPE-V';
UPDATE road_signs SET image_path = 'images/signs/delineation_signs/TYPE-VA.png'  WHERE sign_code = 'TYPE-VA';

-- ZC21-zone (wrong folder 'zoneborden' and wrong file)
UPDATE road_signs
SET image_path = 'images/signs/zone_signs/ZC21 - Zone verboden toegang voor bestuurders van voertuigen waarvan de massa hoger is dan de aangeduide massa.png'
WHERE sign_code = 'ZC21-zone';

-- ZE1-v1: wrong folder 'zoneborden' and wrong filename → canonical ZE1.png (begin-zone)
UPDATE road_signs
SET image_path = 'images/signs/zone_signs/ZE1.png'
WHERE sign_code = 'ZE1-v1';

-- ── B2. road_signs: bulk folder name fixes ────────────────────────────────────

-- 'aanwijzingsborden' folder does not exist → correct folder is 'information_signs'
UPDATE road_signs
SET image_path = REPLACE(image_path, 'images/signs/aanwijzingsborden/', 'images/signs/information_signs/')
WHERE image_path LIKE 'images/signs/aanwijzingsborden/%';

-- 'zoneborden' folder does not exist → correct folder is 'zone_signs'
-- (ZC21-zone and ZE1-v1 already fixed above; this catches any remaining rows)
UPDATE road_signs
SET image_path = REPLACE(image_path, 'images/signs/zoneborden/', 'images/signs/zone_signs/')
WHERE image_path LIKE 'images/signs/zoneborden/%';

-- ── C. Remove D5/D7: no image assets exist, no quiz questions, no road_signs rows ──
DELETE FROM traffic_signs WHERE sign_code IN ('D5', 'D7');

